export class FlatMap<T> {
  map: { [key: string]: T } = {};
  keys: string[] = [];

  constructor(public array: Array<T>, propertyAsKey: keyof T) {
    array.forEach((item: T) => {
      const key = item[propertyAsKey].toString();
      this.map[key] = item;
      this.keys.push(key);
    });
  }
}
