import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  name: 'checkIfBoolean'
})
export class CheckIfBooleanPipe implements PipeTransform {

  transform(value: any, ...args: any[]): any {
    if (typeof value === 'boolean') {
      return value ? 'yes' : 'no';
    }
    return value;
  }

}
