import { Component, Inject, OnDestroy } from '@angular/core';
import { MatDialogRef, MAT_DIALOG_DATA } from '@angular/material/dialog';
import { AutoUnsubscribe } from '@shared/decorators';
import { TableSource } from '@app/pages/table/table.component';
import { FormBuilder, FormControl, FormGroup, Validators } from '@angular/forms';

@AutoUnsubscribe
@Component({
  selector: 'app-table-modal',
  templateUrl: './table-modal.component.html',
  styleUrls: ['./table-modal.component.scss'],
})
export class TableModalComponent implements OnDestroy {

  frm: FormGroup;

  constructor(private _fb: FormBuilder,
              public dialogRef: MatDialogRef<TableModalComponent>,
              @Inject(MAT_DIALOG_DATA) public data: { row: TableSource }) {
    this._initModalForm(this.data.row);
  }

  close(): void {
    this.dialogRef.close();
  }

  delete(): void {
    this.dialogRef.close({ delete: this.data.row.id });
  }

  save(): void {
    console.log(this.frm);
  }

  private _initModalForm(row: TableSource) {
    this.frm = this._fb.group(
      {
        id: [{ value: row.id, disabled: true }],
        date: new FormControl(row.time),
        age: new FormControl(row.age, [Validators.pattern('^[0-9]*$')]),
        description: new FormControl(row.descriptionValue),
      },
    );
  }

  ngOnDestroy(): void {}
}
