import { Injectable } from '@angular/core';
import { ActivatedRouteSnapshot, Resolve, RouterStateSnapshot } from '@angular/router';
import { TableService } from '@app/services/table.service';
import { RequestData } from '@app/commons/models/request-data.interface';
import { Action } from '@app/commons/enums/actions.enum';
import { Status } from '@app/commons/enums/statuses.enum';
import { delay } from 'rxjs/operators';

@Injectable()
export class TableResolver implements Resolve<boolean> {

  constructor(private _tableService: TableService) {}

  resolve(route: ActivatedRouteSnapshot, state: RouterStateSnapshot): boolean {
    this._tableService.setActionStatus({
      action: Action.Load,
      status: Status.Pending,
    });
    this._tableService.loadTable().pipe(delay(700)).subscribe((res: RequestData) => {
        this._tableService.setTableData(res);
        this._tableService.setActionStatus({
          action: Action.Load,
          status: Status.Success,
        });
      },
      error => {
        this._tableService.setActionStatus({
          action: Action.Load,
          status: Status.Error,
        });
      });
    return true;
  }
}
