import { Injectable } from '@angular/core';
import { HttpClient } from '@angular/common/http';

import { BehaviorSubject, Observable, of } from 'rxjs';

import { RequestData } from '@app/commons/models/request-data.interface';
import { ActionStatus } from '@app/commons/models/action-status.interface';
import { Result } from '@app/commons/models/results.model';

@Injectable({
  providedIn: 'root'
})
export class TableService {

  private _tableData = new BehaviorSubject<RequestData>(null);
  private _actonStatus = new BehaviorSubject<ActionStatus>({
    action: null,
    status: null,
  });

  constructor(private _http: HttpClient) {}

  loadTable(): Observable<RequestData> {
    return this._http.get<RequestData>('assets/json/data.json');
  }

  deleteItem(id: Result['eventId']): Observable<boolean>{
    return of(true);
  }

  getTable(): Observable<RequestData> {
    return this._tableData;
  }

  getTableAsValue(): RequestData {
    return this._tableData.value;
  }

  setTableData(data: RequestData): void {
    this._tableData.next(data);
  }

  setActionStatus(actionStatus: ActionStatus): void {
    this._actonStatus.next(actionStatus);
  }

  getActionStatus(): Observable<ActionStatus> {
    return this._actonStatus;
  }
}
