import { ChangeDetectionStrategy, ChangeDetectorRef, Component, OnDestroy, OnInit, ViewChild } from '@angular/core';

import { MatPaginator, MatSort } from '@angular/material';
import { MatTableDataSource } from '@angular/material/table';
import { MatDialog } from '@angular/material/dialog';

import { TableService } from '@app/services/table.service';
import { ObservableHandler } from '@shared/models';
import { RequestData } from '@app/commons/models/request-data.interface';
import { Action } from '@app/commons/enums/actions.enum';
import { Status } from '@app/commons/enums/statuses.enum';
import { AutoUnsubscribe } from '@shared/decorators';
import { RESULT_DATA } from '@app/commons/enums/result-type.enum';
import { Result } from '@app/commons/models/results.model';
import { TableModalComponent } from '@app/pages/table-modal/table-modal.component';
import { Subscription } from 'rxjs';
import { objectCopy } from '@shared/utils';

export interface TableSource {
  id: Result['eventId'];
  time: Result['ageInDays'];
  eventLabel: string;
  icon: string;
  age: number;
  descriptionLabel: string;
  descriptionValue: any;
  type: Result['type'];
}

@AutoUnsubscribe
@Component({
  selector: 'app-table',
  templateUrl: './table.component.html',
  styleUrls: ['./table.component.scss'],
  changeDetection: ChangeDetectionStrategy.OnPush,
})
export class TableComponent implements OnInit, OnDestroy {
  @ViewChild(MatPaginator, { static: true }) paginator: MatPaginator;
  @ViewChild(MatSort, {static: true}) sort: MatSort;

  actionStatus$$ = new ObservableHandler(
    this._tableService.getActionStatus(),
    null,
    this._cdr,
  );

  tableSource = new MatTableDataSource<TableSource>();
  action = Action;

  status = Status;
  displayedColumns: string[] = ['id', 'time', 'eventLabel', 'age', 'descriptionValue'];

  private _preparedTable: Array<TableSource>;
  private _dialogRefSubscription$: Subscription;

  private _tableData$$ = new ObservableHandler(
    this._tableService.getTable(),
    this._initTable.bind(this),
    this._cdr,
  );

  constructor(private _tableService: TableService,
              public dialog: MatDialog,
              private _cdr: ChangeDetectorRef) { }

  ngOnInit(): void {
  }

  showModal(row: TableSource) {
    const dialogRef = this.dialog.open(TableModalComponent, {
      width: '250px',
      data: { row },
    });

    this._dialogRefSubscription$ = dialogRef.afterClosed().subscribe(result => {
      console.log('The dialog was closed', result);
      if (result && result.hasOwnProperty('delete')) {
        this._deleteItem(result.delete);
      }
    });
  }

  private _initTable(tableData: RequestData) {
    if (!tableData) {
      return;
    }

    const resultData = RESULT_DATA.map;
    this._preparedTable = tableData.result.map(item => {
      return {
        id: item.eventId,
        time: item.startDateTime,
        eventLabel: resultData[item.type].eventLabel,
        icon: resultData[item.type].icon,
        age: item.ageInDays,
        descriptionLabel: resultData[item.type].descriptionLabel,
        descriptionValue: item[resultData[item.type].fieldToShow],
        type: item.type,
      };
    });

    this.tableSource = new MatTableDataSource<TableSource>(this._preparedTable);
    this.tableSource.paginator = this.paginator;
    this.tableSource.sort = this.sort;
  }

  private _deleteItem(id: Result['eventId']) {
    this._tableService.setActionStatus({
      action: Action.Delete,
      status: Status.Pending,
    });
    this._tableService.deleteItem(id).subscribe((res: boolean) => {

        const modifiedTable = objectCopy(this._tableService.getTableAsValue());
        const indexToDelete = modifiedTable.result.findIndex(item => item.eventId === id);
        modifiedTable.result.splice(indexToDelete, 1);
        this._tableService.setTableData(modifiedTable);


        this._tableService.setActionStatus({
          action: Action.Delete,
          status: Status.Success,
        });
      },
      error => {
        this._tableService.setActionStatus({
          action: Action.Delete,
          status: Status.Error,
        });
      });
  }

  ngOnDestroy(): void {}
}
